-- Update customers.default_date and customers.pre_filing_dpd_days by account_no.
-- Source: /Users/aof.wisaruth/Downloads/Copy of Payment_หลังพิพากษา_20260430.xlsx / sheet: DPD
-- Rows generated: 2255
-- Generated at: 2026-05-14 23:08:18
--
-- Example:
--   account_no = 700002561225
--   default_date = 2024-02-19
--   pre_filing_dpd_days = 417
--
-- How to use:
-- 1) Test on a copied DB first:
--      cp instance/lqd.db /tmp/lqd_pre_filing_update_test.db
--      sqlite3 /tmp/lqd_pre_filing_update_test.db < update_customers_default_date_pre_filing_dpd.sql
-- 2) Run against the real DB:
--      sqlite3 instance/lqd.db < update_customers_default_date_pre_filing_dpd.sql
--
-- Business rules:
-- - default_date must be YYYY-MM-DD.
-- - pre_filing_dpd_days must be a positive integer.
-- - account_no must exist in active customers.
-- - default_date must be before source_filing_date from the input file.
-- - Rows with validation errors are listed and the script aborts before update.

.headers on
.mode column
.bail on

BEGIN TRANSACTION;

DROP TABLE IF EXISTS _tmp_customer_pre_filing_update;
CREATE TEMP TABLE _tmp_customer_pre_filing_update (
    account_no              TEXT,
    default_date            TEXT,
    pre_filing_dpd_days     INTEGER,
    source_filing_date      TEXT
);


DROP TABLE IF EXISTS _tmp_pre_filing_validation_errors;
CREATE TEMP TABLE _tmp_pre_filing_validation_errors (
    error_type              TEXT NOT NULL,
    account_no              TEXT,
    default_date            TEXT,
    pre_filing_dpd_days     INTEGER,
    source_filing_date      TEXT,
    current_filing_date     TEXT,
    message                 TEXT NOT NULL
);

    error_type, account_no, default_date, pre_filing_dpd_days, source_filing_date, current_filing_date, message
)
SELECT
    'EMPTY_MAPPING',
    NULL,
    NULL,
    NULL,
    NULL,
    NULL,
    'ไม่มีรายการสำหรับ update: กรุณาตรวจสอบ mapping account_no/default_date/pre_filing_dpd_days ก่อนรัน script'
WHERE NOT EXISTS (SELECT 1 FROM _tmp_customer_pre_filing_update);

    error_type, account_no, default_date, pre_filing_dpd_days, source_filing_date, current_filing_date, message
)
SELECT
    'EMPTY_ACCOUNT_NO',
    account_no,
    default_date,
    pre_filing_dpd_days,
    source_filing_date,
    NULL,
    'account_no ว่างใน mapping'
FROM _tmp_customer_pre_filing_update
WHERE TRIM(COALESCE(account_no, '')) = '';

    error_type, account_no, default_date, pre_filing_dpd_days, source_filing_date, current_filing_date, message
)
SELECT
    'DUPLICATE_ACCOUNT_NO',
    TRIM(account_no),
    GROUP_CONCAT(default_date, ', '),
    NULL,
    GROUP_CONCAT(source_filing_date, ', '),
    NULL,
    'พบ account_no ซ้ำใน mapping กรุณาให้เหลือ 1 ค่าเท่านั้น'
FROM _tmp_customer_pre_filing_update
WHERE TRIM(COALESCE(account_no, '')) <> ''
GROUP BY TRIM(account_no)
HAVING COUNT(*) > 1;

    error_type, account_no, default_date, pre_filing_dpd_days, source_filing_date, current_filing_date, message
)
SELECT
    'ACCOUNT_NOT_FOUND',
    TRIM(m.account_no),
    m.default_date,
    m.pre_filing_dpd_days,
    m.source_filing_date,
    NULL,
    'ไม่พบ account_no นี้ใน customers หรือเป็นรายการที่ถูกลบแล้ว'
FROM _tmp_customer_pre_filing_update m
LEFT JOIN customers c
       ON c.account_no = TRIM(m.account_no)
      AND COALESCE(c.is_deleted, 0) = 0
WHERE TRIM(COALESCE(m.account_no, '')) <> ''
  AND c.account_no IS NULL;

    error_type, account_no, default_date, pre_filing_dpd_days, source_filing_date, current_filing_date, message
)
SELECT
    'INVALID_DEFAULT_DATE_FORMAT',
    TRIM(account_no),
    default_date,
    pre_filing_dpd_days,
    source_filing_date,
    NULL,
    'default_date ต้องเป็นรูปแบบ YYYY-MM-DD'
FROM _tmp_customer_pre_filing_update
WHERE TRIM(COALESCE(default_date, '')) NOT GLOB '[0-9][0-9][0-9][0-9]-[0-9][0-9]-[0-9][0-9]'
   OR DATE(default_date) IS NULL;

    error_type, account_no, default_date, pre_filing_dpd_days, source_filing_date, current_filing_date, message
)
SELECT
    'INVALID_PRE_FILING_DPD',
    TRIM(account_no),
    default_date,
    pre_filing_dpd_days,
    source_filing_date,
    NULL,
    'pre_filing_dpd_days ต้องเป็นจำนวนเต็มมากกว่า 0'
FROM _tmp_customer_pre_filing_update
WHERE pre_filing_dpd_days IS NULL
   OR pre_filing_dpd_days <= 0;

    error_type, account_no, default_date, pre_filing_dpd_days, source_filing_date, current_filing_date, message
)
SELECT
    'DEFAULT_NOT_BEFORE_SOURCE_FILING_DATE',
    TRIM(account_no),
    default_date,
    pre_filing_dpd_days,
    source_filing_date,
    NULL,
    'default_date ต้องน้อยกว่า source_filing_date ทุกเคส'
FROM _tmp_customer_pre_filing_update
WHERE DATE(default_date) >= DATE(source_filing_date);

SELECT
    error_type,
    account_no,
    default_date,
    pre_filing_dpd_days,
    source_filing_date,
    current_filing_date,
    message
FROM _tmp_pre_filing_validation_errors
ORDER BY error_type, account_no;

DROP TABLE IF EXISTS _tmp_pre_filing_abort_guard;
CREATE TEMP TABLE _tmp_pre_filing_abort_guard (id INTEGER);

CREATE TEMP TRIGGER _tmp_pre_filing_abort_guard_trigger
BEFORE INSERT ON _tmp_pre_filing_abort_guard
BEGIN
    SELECT RAISE(ABORT, 'ERROR: default_date/pre_filing_dpd_days validation failed. See validation error rows above; no customer rows were updated.');
END;

SELECT 1
WHERE EXISTS (SELECT 1 FROM _tmp_pre_filing_validation_errors);

SELECT COUNT(*) AS input_rows
FROM _tmp_customer_pre_filing_update;

SELECT COUNT(*) AS matched_rows
FROM _tmp_customer_pre_filing_update m
JOIN customers c
  ON c.account_no = TRIM(m.account_no)
 AND COALESCE(c.is_deleted, 0) = 0;

UPDATE customers
SET
    default_date = (
        SELECT m.default_date
        FROM _tmp_customer_pre_filing_update m
        WHERE TRIM(m.account_no) = customers.account_no
        LIMIT 1
    ),
    pre_filing_dpd_days = (
        SELECT m.pre_filing_dpd_days
        FROM _tmp_customer_pre_filing_update m
        WHERE TRIM(m.account_no) = customers.account_no
        LIMIT 1
    ),
    updated_at = CURRENT_TIMESTAMP
WHERE account_no IN (
    SELECT TRIM(account_no)
    FROM _tmp_customer_pre_filing_update
)
AND COALESCE(is_deleted, 0) = 0;

SELECT changes() AS updated_rows;

DROP TABLE IF EXISTS _tmp_pre_filing_abort_guard;
DROP TABLE IF EXISTS _tmp_pre_filing_validation_errors;
DROP TABLE IF EXISTS _tmp_customer_pre_filing_update;

COMMIT;
